LastHandleSnapshot test_last_handle_restore(int initialValue, int updatedValue) {
    // 1. Create a reactive variable with initial value
    auto source = reaction::var(initialValue);

    // 2. Create a calculation with LastHandle policy
    auto calc_node = reaction::calc<reaction::ChangeTrig, reaction::LastHandle>(
        [](int val) { return val * 2; }, source);

    // 3. Get initial result
    int initial_result = calc_node();

    // 4. Update the source variable
