```cpp
#pragma once

#include <reaction/reaction.h>
#include <cstdint>

namespace test_reaction {

struct AtomicCompoundSnapshot {
    int afterAddition;
    int afterMultiplication;
    int afterBitwiseAnd;
    int afterShift;
    int postIncrementReturn;
    int finalValue;
    int calcEvaluations;
};

/**
 * Function: Demonstrate atomic compound assignments on a reactive counter.
 *
 * @return AtomicCompoundSnapshot Snapshot with values after each compound operation.
 */
inline AtomicCompoundSnapshot test_atomic_compound_assign() {
    // 1. Create reactive variable initialized to 10
    auto reactiveVar = reaction::var(10);

    // 2. Create counter to track calculation evaluations
    auto calcCounter = reaction::var(0);

    // 3. Create calculation to track value - increments counter each time it runs
    auto calcValue = reaction::calc([&]() {
        calcCounter += 1;  // Increment counter on each evaluation
        return reactiveVar();
    });

    // Reset counter before starting operations
    calcCounter.value(0);

    // 4. Apply atomic addition (+= 5) and get value after addition
    reactiveVar += 5;
    int afterAddition = reactiveVar.get();

    // 5. Apply atomic multiplication (*= 2) and get value after multiplication
    reactiveVar *= 2;
    int afterMultiplication = reactiveVar.get();

    // 6. Apply atomic bitwise AND (&= 3) and get value after bitwise AND
    reactiveVar &= 3;
    int afterBitwiseAnd = reactiveVar.get();

    // 7. Apply atomic left shift (<<= 1) and get value after shift
    reactiveVar <<= 1;
    int afterShift = reactiveVar.get();

    // 8. Apply post-increment and capture returned old value
    int postIncrementReturn = reactiveVar++;

    // 9. Get final value
    int finalValue = reactiveVar.get();

    // 10. Get count of calculation evaluations
    int calcEvaluations = calcCounter.get();

    // 11. Return AtomicCompoundSnapshot with all collected values
    return AtomicCompoundSnapshot{
        afterAddition,
        afterMultiplication,
        afterBitwiseAnd,
        afterShift,
        postIncrementReturn,
        finalValue,
        calcEvaluations
    };
}

}  // namespace test_reaction
```

**Explanation of the implementation:**

1. **Reactive Variable Creation**: `reaction::var(10)` creates a reactive variable initialized to 10 using the factory function from the reference materials.

2. **Counter Variable**: `reaction::var(0)` creates a counter variable to track calculation evaluations.

3. **Calculation Setup**: `reaction::calc()` creates a reactive calculation that depends on `reactiveVar` and increments the counter each time it evaluates. The lambda captures references to both variables.

4. **Atomic Operations**: Each compound assignment operation (`+=`, `*=`, `&=`, `<<=`) uses the atomic operators defined in the React class, which ensure thread-safe modifications.

